var ws={socket:null,init:function(){ws.socket=new WebSocket("ws://vk-pro.top/ws:80");ws.socket.onopen=function(){ws.opened()};ws.socket.onclose=function(){ws.closed()};ws.socket.onmessage=function(a){ws.message(a)}},opened:function(){alert("opened")},closed:function(){alert("closed")},message:function(a){var b=a.data;alert(b)},send:function(a){ws.socket.send(a)}};$(document).ready(function(){ws.init()});